        zipStream.write(packAdapterJar(descriptor));
        zipStream.closeEntry();
        Map<OSFamily, Bundle> bundles = descriptor.getBundles();
        if (!isPartOfSuite && bundles != null) {
            for (Bundle bundle : bundles.values()) {
