                os.symlink(entry.linkname, path)
        elif entry.islnk():
            target_path = build_path(root_dir, entry.linkname)
            target_st = os.lstat(target_path)
            if (
                st is None
                or st.st_dev != target_st.st_dev
                or st.st_ino != target_st.st_ino
            ):
                print("l", path)
                if st is not None:
                    os.unlink(path)
                os.link(target_path, path)

