static char *dmi_memory_device_size_str(u16 code)
{
	static char size[8];

	if (code == 0)
		strcpy(size, "Empty");
	else if (code == 0xFFFF)
		strcpy(size, "Unknown");
	else
	{
		if (code & 0x8000)
			sprintf(size, "%u kB", code & 0x7FFF);
		else
			sprintf(size, "%u MB", code);
	}

	return size;
}

